// AddTravel.jsx
import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API_BASE = "https://prasa-app-yde3.onrender.com/api";

export default function AddTravel({ employee }) {
  const navigate = useNavigate();

  const [travelDate, setTravelDate] = useState("");
  const [fromLocation, setFromLocation] = useState("");
  const [toLocation, setToLocation] = useState("");
  const [mode, setMode] = useState("");
  const [purpose, setPurpose] = useState("");
  const [amount, setAmount] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!employee || !employee.empld) {
      alert("Employee not found. Please login again.");
      return;
    }

    const payload = {
      empId: employee.empld,
      travel_date: travelDate,
      location_from: fromLocation,
      location_to: toLocation,
      mode_of_travel: mode,
      purpose,
      amount: amount ? Number(amount) : 0,
    };

    try {
      const res = await axios.post(`${API_BASE}/app/travel/add`, payload);
      if (res.data && res.data.success) {
        alert("Travel expense saved!");
        // clear form
        setTravelDate("");
        setFromLocation("");
        setToLocation("");
        setMode("");
        setPurpose("");
        setAmount("");
        // optional: navigate to travel history
        navigate("/travel-history");
      } else {
        alert(res.data?.message || "Failed to save travel expense");
      }
    } catch (err) {
      console.error("AddTravel error:", err);
      alert("Server error while saving travel");
    }
  };

  const green = "#0f9d58";
  const light = "#eaf8f0";

  return (
    <div
      style={{
        background: light,
        minHeight: "100vh",
        padding: 20,
        display: "flex",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 780,
          background: "#fff",
          borderRadius: 18,
          padding: 20,
          boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => navigate("/addnew")}
            style={{
              background: light,
              border: "none",
              padding: "8px 12px",
              borderRadius: 10,
              cursor: "pointer",
            }}
          >
            ←
          </button>
          <h2 style={{ margin: 0, color: green }}>Add Travel Expense</h2>
        </div>

        <p style={{ marginTop: 8, color: "#555" }}>
          Employee: {employee?.name} • {employee?.empld}
        </p>

        <form onSubmit={handleSubmit} style={{ marginTop: 15 }}>
          <div style={{ marginBottom: 10 }}>
            <label>Date</label>
            <input
              type="date"
              value={travelDate}
              onChange={(e) => setTravelDate(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
              required
            />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label>From</label>
            <input
              type="text"
              value={fromLocation}
              onChange={(e) => setFromLocation(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label>To</label>
            <input
              type="text"
              value={toLocation}
              onChange={(e) => setToLocation(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label>Mode of Travel</label>
            <input
              type="text"
              value={mode}
              onChange={(e) => setMode(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <div style={{ marginBottom: 10 }}>
            <label>Purpose</label>
            <input
              type="text"
              value={purpose}
              onChange={(e) => setPurpose(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <div style={{ marginBottom: 16 }}>
            <label>Amount</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              style={{ width: "100%", padding: 8, borderRadius: 8, border: "1px solid #ccc" }}
            />
          </div>

          <button
            type="submit"
            style={{
              width: "100%",
              background: green,
              color: "#fff",
              border: "none",
              borderRadius: 10,
              padding: 12,
              cursor: "pointer",
              fontSize: 16,
            }}
          >
            Save Travel
          </button>
        </form>
      </div>
    </div>
  );
}
